code = """import json
import re

# Load NPM packages data
with open(locals()['var_functions.query_db:52']) as f:
    npm_packages = json.load(f)

# Load project mappings
with open(locals()['var_functions.query_db:34']) as f:
    project_mappings = json.load(f)

# Load GitHub project info
with open(locals()['var_functions.query_db:66']) as f:
    github_projects = json.load(f)

# Step 1: Find latest release for each NPM package
latest_releases = {}
for pkg in npm_packages:
    try:
        # VersionInfo is a JSON string, parse it
        vinfo_str = pkg['VersionInfo']
        vinfo = json.loads(vinfo_str.replace('\n', ' ').replace('\r', '').strip())
        if vinfo.get('IsRelease'):
            name = pkg['Name']
            ordinal = vinfo['Ordinal']
            if name not in latest_releases or ordinal > latest_releases[name]['ordinal']:
                latest_releases[name] = {
                    'version': pkg['Version'],
                    'ordinal': ordinal
                }
    except:
        continue

print(f'Found {len(latest_releases)} latest package releases')

# Step 2: Map package+version to GitHub repository
github_map = {}
for mapping in project_mappings:
    if mapping.get('ProjectType') == 'GITHUB':
        github_map[(mapping['Name'], mapping['Version'])] = mapping['ProjectName']

print(f'GitHub project mappings: {len(github_map)}')

# Step 3: Extract GitHub star counts
stars_map = {}
for project in github_projects:
    info = project['Project_Information']
    # Find repository name in format owner/repo
    m = re.search(r'project\s+([^\s]+/[^\s]+)', info)
    if m:
        repo = m.group(1)
        # Extract star count
        m2 = re.search(r'([\d,]+)\s+stars', info)
        if m2:
            stars = int(m2.group(1).replace(',', ''))
            stars_map[repo] = stars

print(f'Repositories with star data: {len(stars_map)}')

# Step 4: Combine and rank by stars
candidates = []
for name, data in latest_releases.items():
    key = (name, data['version'])
    if key in github_map:
        repo = github_map[key]
        if repo in stars_map:
            candidates.append({
                'PackageName': name,
                'Version': data['version'],
                'GitHubRepository': repo,
                'Stars': stars_map[repo]
            })

print(f'Matched packages: {len(candidates)}')

# Step 5: Get top 5 packages by GitHub stars
if candidates:
    top5 = sorted(candidates, key=lambda x: x['Stars'], reverse=True)[:5]
    
    print('\n=== TOP 5 NPM PACKAGES BY GITHUB STARS (Latest Release) ===')
    for i, pkg in enumerate(top5, 1):
        print(f"{i}. {pkg['PackageName']}")
        print(f"   Version: {pkg['Version']}")
        print(f"   GitHub: {pkg['GitHubRepository']}")
        print(f"   Stars: {pkg['Stars']:,}")
        print()
else:
    top5 = []
    print('No matching packages found')

# Return final result
result = {'top_packages': top5}
print('__RESULT__:')
print(json.dumps(result))"""

